        item := minValue;

        // Shift elements down to remove the minimum
        i := minIndex;
        WHILE i < top DO
            stack[i] := stack[i + 1];
            i := i + 1;
        END_WHILE;

        // Decrement top
        top := top - 1;

        error := FALSE;
        status := 16#0000;
    END_IF;
