FUNCTION_BLOCK FB_CalculateDayOfYear
VAR_INPUT
    Year : INT;
    Month : INT;
    Day : INT;
END_VAR

VAR_OUTPUT
    DayOfYear : INT;
    error : BOOL;
    status : E_Status;
END_VAR

VAR
    DaysInMonth : ARRAY[1..12] OF INT := [31, 28, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31];
END_VAR

VAR_TEMP
    i : INT;
    bIsLeapYear : BOOL;
    iMaxDayForMonth : INT;
END_VAR

    // Initialize outputs
    DayOfYear := 0;
    error := FALSE;
    status := STATUS_OK;

    // 1. Validate month (highest priority)
    IF (Month < 1) OR (Month > 12) THEN
        error := TRUE;
        status := STATUS_INVALID_MONTH;
        RETURN;
    END_IF;

    // 2. Determine leap year status (needed for day validation)
    // Leap year rule: divisible by 4 AND NOT divisible by 100, OR divisible by 400
    bIsLeapYear := ((Year MOD 4) = 0) AND ((Year MOD 100) <> 0) OR ((Year MOD 400) = 0);

    // 3. Validate day (depends on month and leap year status)
    // Get maximum days for the given month
    iMaxDayForMonth := DaysInMonth[Month];

    // Special handling for February in leap years
    IF (Month = 2) AND bIsLeapYear THEN
        iMaxDayForMonth := 29;
    END_IF;

    // Check day validity: must be positive and not exceed maximum for month
    IF (Day < 1) OR (Day > iMaxDayForMonth) THEN
        error := TRUE;
        status := STATUS_INVALID_DAY;
        RETURN;
    END_IF;

    // 4. Validate year (lowest priority)
    IF (Year < 1000) OR (Year > 3000) THEN
        error := TRUE;
        status := STATUS_INVALID_YEAR;
        RETURN;
    END_IF;

    // 5. Calculate day of year for valid inputs
    // Sum days from all completed months (months before current month)
    FOR i := 1 TO Month-1 DO
        DayOfYear := DayOfYear + DaysInMonth[i];
    END_FOR;

    // Add current day
    DayOfYear := DayOfYear + Day;

    // Add 1 for leap years if date is after February
    IF bIsLeapYear AND (Month > 2) THEN
        DayOfYear := DayOfYear + 1;
    END_IF;

END_FUNCTION_BLOCK

FUNCTION_BLOCK SelectSort
VAR_INPUT
    exe : BOOL;
    seq : ARRAY[1..100] OF INT;
END_VAR
VAR_OUTPUT
    error : BOOL;
    status : WORD;
END_VAR
VAR
    i : INT;
    j : INT;
    min_idx : INT;
    temp : INT;
    n : INT := 100;
    seq_local : ARRAY[1..100] OF INT;
    exe_prev : BOOL;
    sortValid : BOOL;
END_VAR

(* Rising edge detection for single execution *)
IF exe AND NOT exe_prev THEN
    (* Initialize outputs to failure state *)
    error := TRUE;
    status := 16#8A01;
    sortValid := TRUE;

    (* Copy input array to local working array *)
    FOR i := 1 TO n DO
        seq_local[i] := seq[i];
    END_FOR;

    (* Selection sort algorithm *)
    FOR i := 1 TO n-1 DO
        min_idx := i;
        FOR j := i+1 TO n DO
            IF seq_local[j] < seq_local[min_idx] THEN
                min_idx := j;
            END_IF;
        END_FOR;

        IF min_idx <> i THEN
            temp := seq_local[i];
            seq_local[i] := seq_local[min_idx];
            seq_local[min_idx] := temp;
        END_IF;
    END_FOR;

    (* Verify array is sorted in ascending order *)
    FOR i := 1 TO n-1 DO
        IF seq_local[i] > seq_local[i+1] THEN
            sortValid := FALSE;
            EXIT;
        END_IF;
    END_FOR;

    (* If verification passed, write back results and set success status *)
    IF sortValid THEN
        FOR i := 1 TO n DO
            seq[i] := seq_local[i];
        END_FOR;

        error := FALSE;
        status := 16#0000;
    END_IF;
END_IF;

(* Update edge detection variable *)
exe_prev := exe;

END_FUNCTION_BLOCK

