(* ========================================================================
   FUNCTION_BLOCK: FB_AnalogBatchConverter
   Description: Batch converter for analog input signals with configurable
                scaling and temperature modes. Processes up to 10 channels
                in parallel using configuration arrays.
   Author: Senior PLC Commissioning Engineer
   IEC 61131-3 Compliant
   ======================================================================== *)

FUNCTION_BLOCK FB_AnalogBatchConverter
VAR_INPUT
    (* Number of active channels to process (1..10) *)
    count : INT;
    (* Array of raw analog input values (ADC counts) *)
    analogValues : ARRAY[1..10] OF REAL;
END_VAR

VAR_OUTPUT
    (* Parallel configuration and result arrays *)
    channel_enable : ARRAY[1..10] OF BOOL;
    channel_hiLIM : ARRAY[1..10] OF REAL;
    channel_loLIM : ARRAY[1..10] OF REAL;
    channel_bipolar : ARRAY[1..10] OF BOOL;
    channel_measuringMode : ARRAY[1..10] OF INT;
    channel_retVal : ARRAY[1..10] OF WORD;
    channel_outputValue : ARRAY[1..10] OF REAL;
END_VAR

VAR
    i : INT;                    (* Loop counter *)
    rawValue : REAL;            (* Temporary storage for raw input *)
    normalizedValue : REAL;     (* Normalized value for scaling *)
    rangeInput : REAL;          (* Input range span *)
    rangeOutput : REAL;         (* Output range span *)
    tempOutput : REAL;          (* Temporary output calculation *)
END_VAR

(* Main processing loop *)
FOR i := 1 TO 10 DO
    (* Only process if within active count range AND channel is enabled *)
    IF (i <= count) AND channel_enable[i] THEN
        (* Initialize return value for this channel *)
        channel_retVal[i] := 0;
        rawValue := analogValues[i];

        CASE channel_measuringMode[i] OF
            0: (* Non-temperature measurement *)
                (* Error Check 2: Validate limits *)
                IF channel_hiLIM[i] <= channel_loLIM[i] THEN
                    channel_retVal[i] := 16#8002;  (* Limit violation error *)
                    channel_outputValue[i] := 0.0;  (* Clear output on error *)
                ELSE
                    (* Calculate input range based on bipolar setting *)
                    IF channel_bipolar[i] THEN
                        rangeInput := 55296.0;  (* -27648 to +27648 *)
                        normalizedValue := (rawValue + 27648.0) / rangeInput;
                    ELSE
                        rangeInput := 27648.0;  (* 0 to 27648 *)
                        normalizedValue := rawValue / rangeInput;
                    END_IF;

                    (* Clamp normalized value to valid range [0,1] *)
                    IF normalizedValue < 0.0 THEN
                        normalizedValue := 0.0;
                    ELSIF normalizedValue > 1.0 THEN
                        normalizedValue := 1.0;
                    END_IF;

                    (* Calculate scaled output *)
                    rangeOutput := channel_hiLIM[i] - channel_loLIM[i];
                    channel_outputValue[i] := channel_loLIM[i] + (normalizedValue * rangeOutput);
                END_IF;

            1: (* Standard temperature measurement *)
                channel_outputValue[i] := rawValue / 10.0;

            2: (* Climatic temperature measurement *)
                channel_outputValue[i] := rawValue / 100.0;

            ELSE
                (* Error Check 1: Invalid measuring mode *)
                channel_retVal[i] := 16#8001;  (* Invalid mode error *)
                channel_outputValue[i] := 0.0;  (* Clear output on error *)
        END_CASE;
    ELSE
        (* Channel not enabled or outside active count range *)
        channel_outputValue[i] := 0.0;
        channel_retVal[i] := 0;
    END_IF;
END_FOR;

END_FUNCTION_BLOCK;

FUNCTION_BLOCK FB_HexDigitAnalyzer
VAR_INPUT
    InputNumber : INT;
END_VAR
VAR_OUTPUT
    Thousands : INT;
    Hundreds : INT;
    Tens : INT;
    Ones : INT;
    MinDigit : INT;
    error : BOOL;
    status : WORD;
END_VAR
VAR
    tempMin : INT;
    digitVal : INT;
END_VAR

(* Input Validation *)
IF (InputNumber < 0) OR (InputNumber > 9999) THEN
    (* Error Condition *)
    error := TRUE;
    status := 16#8001;
    Thousands := 0;
    Hundreds := 0;
    Tens := 0;
    Ones := 0;
    MinDigit := 0;
ELSE
    (* Valid Input Processing *)
    error := FALSE;
    status := 16#0000;

    (* Digit Separation *)
    Thousands := InputNumber / 1000;
    Hundreds := (InputNumber MOD 1000) / 100;
    Tens := (InputNumber MOD 100) / 10;
    Ones := InputNumber MOD 10;

    (* Minimum Non-Zero Digit Detection *)
    tempMin := 32767; (* Maximum INT value *)

    (* Check Thousands digit *)
    digitVal := Thousands;
    IF digitVal <> 0 THEN
        tempMin := minimal(tempMin, digitVal);
    END_IF;

    (* Check Hundreds digit *)
    digitVal := Hundreds;
    IF digitVal <> 0 THEN
        tempMin := minimal(tempMin, digitVal);
    END_IF;

    (* Check Tens digit *)
    digitVal := Tens;
    IF digitVal <> 0 THEN
        tempMin := minimal(tempMin, digitVal);
    END_IF;

    (* Check Ones digit *)
    digitVal := Ones;
    IF digitVal <> 0 THEN
        tempMin := minimal(tempMin, digitVal);
    END_IF;

    (* Determine final MinDigit output *)
    IF tempMin = 32767 THEN
        (* No non-zero digits found *)
        MinDigit := 0;
    ELSE
        MinDigit := tempMin;
    END_IF;
END_IF;

END_FUNCTION_BLOCK;

TYPE
    // Enumeration for sort direction (for internal clarity)
    SortDirectionEnum : (Ascending, Descending);

    // Enumeration for status codes (mapping to required WORD values)
    ShellSortStatusEnum : (Success := 16#0000, SizeTooSmall := 16#8200, SizeTooLarge := 16#8201);
END_TYPE

FUNCTION_BLOCK ShellSortFB
VAR_INPUT
    // Input Variables
    sortDirection : BOOL;  // FALSE = Ascending, TRUE = Descending
    arr : ARRAY[1..1000] OF DINT;  // Fixed-length input array
END_VAR

VAR_OUTPUT
    // Output Variables
    error : BOOL;  // FALSE: No error, TRUE: Error occurred
    status : WORD;  // Status code (16#0000, 16#8200, or 16#8201)
    sorted_arr : ARRAY[1..1000] OF DINT;  // Sorted output array
END_VAR

VAR
    // Algorithm Variables
    gap : DINT;
    i : DINT;
    j : DINT;
    temp : DINT;
    n : DINT := 1000;  // Fixed array size
    dirMultiplier : DINT;  // Direction multiplier for comparison

    // Internal State
    internalStatus : ShellSortStatusEnum;
END_VAR

// 1. Copy input array to output array
sorted_arr := arr;

// 2. Initialize default status (no error)
error := FALSE;
status := 16#0000;
internalStatus := Success;

// 3. Validate array size against fixed constraints
IF n <= 1 THEN
    error := TRUE;
    internalStatus := SizeTooSmall;
ELSIF n > 1000 THEN
    error := TRUE;
    internalStatus := SizeTooLarge;
END_IF;

// 4. Map internal status to output WORD
CASE internalStatus OF
    Success: status := 16#0000;
    SizeTooSmall: status := 16#8200;
    SizeTooLarge: status := 16#8201;
END_CASE;

// 5. If validation failed, return immediately
IF error THEN
    RETURN;
END_IF;

// 6. Set direction multiplier for comparison logic
// For ascending (sortDirection = FALSE): multiplier = 1
// For descending (sortDirection = TRUE): multiplier = -1
IF sortDirection THEN
    dirMultiplier := -1;
ELSE
    dirMultiplier := 1;
END_IF;

// 7. Implement Shell Sort algorithm with optimized gap sequence for 1000 elements
// Using gap sequence: 1000, 500, 250, 125, 62, 31, 15, 7, 3, 1
gap := 1000;
WHILE gap > 0 DO
    i := gap + 1;
    WHILE i <= n DO
        temp := sorted_arr[i];
        j := i;

        // Modified comparison for direction control
        // (sorted_arr[j - gap] - temp) * dirMultiplier > 0
        // This handles both ascending and descending orders
        WHILE (j > gap) AND ((sorted_arr[j - gap] - temp) * dirMultiplier > 0) DO
            sorted_arr[j] := sorted_arr[j - gap];
            j := j - gap;
        END_WHILE;

        sorted_arr[j] := temp;
        i := i + 1;
    END_WHILE;

    // Update gap for next iteration
    CASE gap OF
        1000: gap := 500;
        500: gap := 250;
        250: gap := 125;
        125: gap := 62;
        62: gap := 31;
        31: gap := 15;
        15: gap := 7;
        7: gap := 3;
        3: gap := 1;
        1: gap := 0;
    END_CASE;
END_WHILE;

END_FUNCTION_BLOCK;

FUNCTION_BLOCK FloatingAverage
VAR_INPUT
    cyclicExecution : BOOL; (* When TRUE, periodic reading is performed, and trigger has no effect *)
    trigger : BOOL; (* External trigger signal, reads value upon each rising edge *)
    value : REAL; (* Newly read data value *)
    windowSize : INT; (* The window size for the moving average, which must be between 1 and 100 *)
    reset : BOOL; (* Reset signal, resets the moving average calculation when TRUE *)
END_VAR
VAR_OUTPUT
    average : REAL; (* The moving average *)
    windowSizeReached : BOOL; (* FALSE: Maximum window width not yet reached, TRUE: Maximum window width has been reached *)
    error : BOOL; (* FALSE: No error occurred, TRUE: An error occurred during the execution of FB *)
    status : WORD; (* Status code *)
END_VAR
VAR
    (* Data buffer and management *)
    dataBuffer : ARRAY[1..100] OF REAL; (* Circular buffer for data values *)
    bufferIndex : INT := 1; (* Current insertion index in the circular buffer *)
    sampleCount : INT := 0; (* Number of valid samples currently in the buffer *)
    sum : REAL := 0.0; (* Running sum of the valid samples in the buffer *)

    (* Edge detection and state tracking *)
    triggerPrev : BOOL := FALSE; (* Previous state of trigger for rising edge detection *)
    cyclicPrev : BOOL := FALSE; (* Previous state of cyclicExecution for edge detection *)

    (* Internal validated window size *)
    internalWindowSize : INT := 1;
END_VAR

(* ================================ *)
(* RESET LOGIC - Highest Priority   *)
(* ================================ *)
IF reset THEN
    (* Clear the data buffer *)
    FOR bufferIndex := 1 TO 100 DO
        dataBuffer[bufferIndex] := 0.0;
    END_FOR;

    (* Reset all internal state variables *)
    bufferIndex := 1;
    sampleCount := 0;
    sum := 0.0;
    triggerPrev := FALSE;
    cyclicPrev := FALSE;

    (* Reset outputs *)
    average := 0.0;
    windowSizeReached := FALSE;
    error := FALSE;
    status := 16#0000; (* Execution successful *)

    (* Validate and set internal window size after reset *)
    IF (windowSize >= 1) AND (windowSize <= 100) THEN
        internalWindowSize := windowSize;
    ELSE
        internalWindowSize := 1; (* Default to minimum valid size *)
    END_IF;

    RETURN; (* Exit function block after reset *)
END_IF;

(* ================================ *)
(* WINDOW SIZE VALIDATION           *)
(* ================================ *)
IF (windowSize < 1) OR (windowSize > 100) THEN
    error := TRUE;
    status := 16#8200; (* Window length setting error *)
    average := 0.0;
    windowSizeReached := FALSE;
    RETURN; (* Exit function block on error *)
ELSE
    error := FALSE;
    status := 16#0000; (* Execution successful *)
    internalWindowSize := windowSize;
END_IF;

(* ================================ *)
(* DATA ACQUISITION LOGIC           *)
(* ================================ *)
IF cyclicExecution THEN
    (* Cyclic mode: process every scan *)
    IF NOT cyclicPrev THEN
        cyclicPrev := TRUE; (* Set for next scan *)

        (* Store the old value that will be overwritten *)
        oldValue : REAL;
        IF sampleCount >= internalWindowSize THEN
            (* Buffer is full, calculate index of oldest value to be overwritten *)
            oldValue := dataBuffer[((bufferIndex - internalWindowSize - 1 + 100) MOD 100) + 1];
        ELSE
            oldValue := 0.0; (* No value to remove when buffer not full *)
        END_IF;

        (* Update buffer with new value *)
        dataBuffer[bufferIndex] := value;

        (* Update running sum *)
        sum := sum + value - oldValue;

        (* Update buffer index (circular) *)
        bufferIndex := (bufferIndex MOD 100) + 1;

        (* Update sample count (capped at window size) *)
        IF sampleCount < internalWindowSize THEN
            sampleCount := sampleCount + 1;
        END_IF;
    END_IF;

    (* Reset trigger edge detection in cyclic mode *)
    triggerPrev := FALSE;
ELSE
    (* Triggered mode: only process on rising edge of trigger *)
    cyclicPrev := FALSE; (* Reset cyclic edge detection *)

    IF trigger AND NOT triggerPrev THEN
        (* Rising edge detected *)
        triggerPrev := TRUE;

        (* Store the old value that will be overwritten *)
        oldValue : REAL;
        IF sampleCount >= internalWindowSize THEN
            (* Buffer is full, calculate index of oldest value to be overwritten *)
            oldValue := dataBuffer[((bufferIndex - internalWindowSize - 1 + 100) MOD 100) + 1];
        ELSE
            oldValue := 0.0; (* No value to remove when buffer not full *)
        END_IF;

        (* Update buffer with new value *)
        dataBuffer[bufferIndex] := value;

        (* Update running sum *)
        sum := sum + value - oldValue;

        (* Update buffer index (circular) *)
        bufferIndex := (bufferIndex MOD 100) + 1;

        (* Update sample count (capped at window size) *)
        IF sampleCount < internalWindowSize THEN
            sampleCount := sampleCount + 1;
        END_IF;
    ELSIF NOT trigger THEN
        (* Reset edge detection when trigger goes low *)
        triggerPrev := FALSE;
    END_IF;
END_IF;

(* ================================ *)
(* AVERAGE CALCULATION              *)
(* ================================ *)
IF sampleCount > 0 THEN
    (* Safe division - sampleCount is guaranteed > 0 *)
    average := sum / INT_TO_REAL(sampleCount);

    (* Update windowSizeReached flag *)
    windowSizeReached := (sampleCount >= internalWindowSize);
ELSE
    (* No samples yet *)
    average := 0.0;
    windowSizeReached := FALSE;
END_IF;

END_FUNCTION_BLOCK;

