FUNCTION_BLOCK TruckGarage
VAR_INPUT
    enter_flag : BOOL;
    exit_flag : BOOL;
    VehicleNumber_in : INT;
END_VAR
VAR_OUTPUT
    truck : T_TRUCK_INFO;
END_VAR
VAR_IN_OUT
    garage : ARRAY[1..3, 1..5] OF T_GARAGE_SLOT;
END_VAR
VAR
    i : INT;
    j : INT;
    CurrentState : INT := 0;
    NextState : INT := 0;
    EntryFound : BOOL;
    ExitFound : BOOL;
END_VAR

(* State Definitions *)
(* 0: IDLE, 1: ENTRY_PROCESSING, 2: EXIT_PROCESSING *)

(* State Transition *)
CurrentState := NextState;

CASE CurrentState OF
    0: (* IDLE *)
        (* Clear output *)
        truck.row := 0;
        truck.col := 0;
        truck.VehicleNumber := 0;
        EntryFound := FALSE;
        ExitFound := FALSE;

        (* Priority: Entry over Exit if both flags are active *)
        IF enter_flag THEN
            NextState := 1; (* Go to ENTRY_PROCESSING *)
        ELSIF exit_flag THEN
            NextState := 2; (* Go to EXIT_PROCESSING *)
        ELSE
            NextState := 0; (* Stay in IDLE *)
        END_IF;

    1: (* ENTRY_PROCESSING *)
        (* Search from last row to first, last column to first *)
        i := 3;
        WHILE i >= 1 AND NOT EntryFound DO
            j := 5;
            WHILE j >= 1 AND NOT EntryFound DO
                IF NOT garage[i,j].Occupied THEN
                    (* Allocate space *)
                    garage[i,j].Occupied := TRUE;
                    garage[i,j].VehicleNumber := VehicleNumber_in;
                    EntryFound := TRUE;
                END_IF;
                j := j - 1;
            END_WHILE;
            i := i - 1;
        END_WHILE;
        NextState := 0; (* Always return to IDLE *)

    2: (* EXIT_PROCESSING *)
        (* Search from first row to last, first column to last *)
        i := 1;
        WHILE i <= 3 AND NOT ExitFound DO
            j := 1;
            WHILE j <= 5 AND NOT ExitFound DO
                IF garage[i,j].Occupied THEN
                    (* Release space and output info *)
                    truck.row := i;
                    truck.col := j;
                    truck.VehicleNumber := garage[i,j].VehicleNumber;
                    garage[i,j].Occupied := FALSE;
                    garage[i,j].VehicleNumber := 0;
                    ExitFound := TRUE;
                END_IF;
                j := j + 1;
            END_WHILE;
            i := i + 1;
        END_WHILE;
        NextState := 0; (* Always return to IDLE *)

    ELSE
        NextState := 0; (* Fallback to IDLE *)
END_CASE;

END_FUNCTION_BLOCK

FUNCTION_BLOCK FB_MergeBytes
VAR_INPUT
    byteArray : ARRAY[1..20] OF DINT; (* Each DINT element holds one byte value (0-255) *)
END_VAR
VAR_OUTPUT
    dwordArray : ARRAY[1..10] OF DINT; (* Each DINT will hold 4 merged bytes *)
    mergeDwordNum : DINT; (* Actual number of successfully merged double words *)
END_VAR
VAR
    iByteIndex : DINT; (* Index for traversing byteArray *)
    iDwordIndex : DINT; (* Index for traversing dwordArray *)
    iByteInGroup : DINT; (* Index within a 4-byte group (0-3) *)
    tempDword : DINT; (* Temporary storage for building the double word *)
    currentByte : DINT; (* Temporary storage for a single byte value *)
END_VAR
VAR CONSTANT
    BYTE_ARRAY_SIZE : DINT := 20;
    DWORD_ARRAY_SIZE : DINT := 10;
    BYTES_PER_DWORD : DINT := 4;
END_VAR

(* Initialize output count *)
mergeDwordNum := 0;

(* Clear the output array to ensure predictable state *)
FOR iDwordIndex := 1 TO DWORD_ARRAY_SIZE DO
    dwordArray[iDwordIndex] := 0;
END_FOR;

(* Main merging loop *)
iByteIndex := 1;
iDwordIndex := 1;

WHILE (iByteIndex + (BYTES_PER_DWORD - 1) <= BYTE_ARRAY_SIZE) AND (iDwordIndex <= DWORD_ARRAY_SIZE) DO
    (* Initialize the temporary double word for this group *)
    tempDword := 0;

    (* Combine 4 consecutive bytes into one double word *)
    FOR iByteInGroup := 0 TO BYTES_PER_DWORD-1 DO
        (* Extract the lowest 8 bits (one byte) from the DINT element *)
        currentByte := byteArray[iByteIndex + iByteInGroup] AND 16#000000FF;

        (* Shift the byte to its correct position and OR it into the temporary double word *)
        tempDword := tempDword OR SHL(currentByte, iByteInGroup * 8);
    END_FOR;

    (* Store the merged double word and update counters *)
    dwordArray[iDwordIndex] := tempDword;
    mergeDwordNum := mergeDwordNum + 1;

    (* Move to the next group of bytes and the next double word slot *)
    iByteIndex := iByteIndex + BYTES_PER_DWORD;
    iDwordIndex := iDwordIndex + 1;
END_WHILE;

END_FUNCTION_BLOCK;

