StartButtonPrev := StartButton;

UpperLimitEdge := UpperLimit AND NOT UpperLimitPrev;
UpperLimitPrev := UpperLimit;

LowerLimitEdge := LowerLimit AND NOT LowerLimitPrev;
LowerLimitPrev := LowerLimit;

