        DoughRollerMotor := FALSE;
        ToppingDispenser := FALSE;
        ConveyorMotor := FALSE;
        OvenHeater := FALSE;
        OvenTemperature := 0;
        SystemActive := FALSE;
        State := PizzaState.Idle;

    ELSE
        (* Fallback to safe state *)
        State := PizzaState.Idle;
        SystemActive := FALSE;
        DoughRollerMotor := FALSE;
        ToppingDispenser := FALSE;
        ConveyorMotor := FALSE;
        OvenHeater := FALSE;
        OvenTemperature := 0;
END_CASE;

