    Open_CB1_66KV : BOOL;
    Open_CB2_66KV : BOOL;
    Open_CB_TRSF1 : BOOL;
    Open_CB2_22KV : BOOL;
END_VAR

VAR
    Threshold500 : INT := 500;
    Prev_States : ST_CircuitBreakerStates;
    Next_States : ST_CircuitBreakerStates;
    bShortCircuitDetected : BOOL;
END_VAR

(* 1. SHORT CIRCUIT DETECTION (Independent of Reset) *)
Short_Circuit_66BUS := (Current_Fault_on_66BUS1 > Threshold500);
Short_Circuit_TRSF1 := (Current_Fault_on_TRSF1 > Threshold500);

(* 2. RESET OVERRIDE - All breakers to FALSE (Closed) except CB2_66KV *)
IF Reset_All_CB THEN
    Next_States.Open_CB2_22KV := FALSE;
    Next_States.Open_CB1_66KV := FALSE;
    Next_States.Open_CB_TRSF1 := FALSE;
    Next_States.Open_CB2_66KV := TRUE; (* Per specification *)
ELSE
    (* 3. CALCULATE NEXT STATES BASED ON PREVIOUS SCAN CYCLE *)
    (* Initialize with previous state - prevents rapid switching *)
    Next_States := Prev_States;

    (* Combined short circuit flag for logic simplification *)
    bShortCircuitDetected := Short_Circuit_66BUS OR Short_Circuit_TRSF1;

    (* --- FIRST PASS LOGIC (as per specification order) --- *)
    (* Open_CB2_22KV - First Condition *)
    IF (NOT Prev_States.Open_CB2_22KV) AND 
       ((Prev_States.Open_CB1_66KV AND Prev_States.Open_CB_TRSF1) OR Short_Circuit_66BUS) THEN
        Next_States.Open_CB2_22KV := TRUE;
    END_IF;

    (* Open_CB1_66KV - First Condition *)
    IF (NOT Next_States.Open_CB2_22KV) AND 
       ((Prev_States.Open_CB1_66KV AND Prev_States.Open_CB_TRSF1) OR Short_Circuit_66BUS) THEN
        Next_States.Open_CB1_66KV := TRUE;
    END_IF;

    (* Open_CB_TRSF1 - First Condition *)
    IF (NOT Next_States.Open_CB2_22KV) AND 
       ((Next_States.Open_CB1_66KV AND Prev_States.Open_CB_TRSF1) OR Short_Circuit_66BUS) THEN
        Next_States.Open_CB_TRSF1 := TRUE;
    END_IF;

    (* Open_CB2_66KV - Always TRUE per specification *)
    Next_States.Open_CB2_66KV := TRUE;

    (* --- SECOND PASS LOGIC (Updates as per specification) --- *)
    (* Update Open_CB2_22KV again *)
    IF (NOT Prev_States.Open_CB2_22KV) AND 
       ((Next_States.Open_CB2_66KV AND Next_States.Open_CB1_66KV AND Next_States.Open_CB_TRSF1) OR Short_Circuit_TRSF1) THEN
        Next_States.Open_CB2_22KV := TRUE;
    END_IF;

    (* Update Open_CB1_66KV again *)
    IF (NOT Next_States.Open_CB2_22KV) AND 
       ((Next_States.Open_CB2_66KV AND Prev_States.Open_CB1_66KV AND Next_States.Open_CB_TRSF1) OR Short_Circuit_TRSF1) THEN
        Next_States.Open_CB1_66KV := TRUE;
    END_IF;

    (* Update Open_CB_TRSF1 again *)
    IF (NOT Next_States.Open_CB2_22KV) AND 
       ((Next_States.Open_CB2_66KV AND Next_States.Open_CB1_66KV AND Prev_States.Open_CB_TRSF1) OR Short_Circuit_TRSF1) THEN
        Next_States.Open_CB_TRSF1 := TRUE;
    END_IF;

    (* 4. FAILSAFE: If any short circuit is detected, ensure critical breakers open *)
    IF bShortCircuitDetected THEN
        Next_States.Open_CB1_66KV := TRUE;
        Next_States.Open_CB_TRSF1 := TRUE;
        Next_States.Open_CB2_22KV := TRUE;
    END_IF;
END_IF;

(* 5. ASSIGN NEXT STATES TO OUTPUTS *)
Open_CB2_22KV := Next_States.Open_CB2_22KV;
Open_CB1_66KV := Next_States.Open_CB1_66KV;
Open_CB_TRSF1 := Next_States.Open_CB_TRSF1;
Open_CB2_66KV := Next_States.Open_CB2_66KV;

(* 6. STORE CURRENT STATES FOR NEXT SCAN CYCLE *)
Prev_States := Next_States;

END_FUNCTION_BLOCK;

FUNCTION_BLOCK FB_AdvancedCircuitBreakerControl
VAR_INPUT
    S_AL1_P_B1 : BOOL;
    S_AL1_P_B2 : BOOL;
    S_AL1_MCB : BOOL;
    MCB_BUSY : BOOL;
    MCB_ERROR : BOOL;
    S_AL1_MCBR : BOOL;
    MCBR_BUSY : BOOL;
    MCBR_ERROR : BOOL;
    S_AL1_P_B3 : BOOL;
    S_AL1_MCB2 : BOOL;
    S_AL1_MCBR2 : BOOL;
END_VAR
VAR_OUTPUT
    E_AL1_B1 : BOOL;
    PUWS_AL1_B1_PLUS : BOOL;
    PUWS_AL1_B1_RIGHT : BOOL;
    PAS_AL1_PLUS : BOOL;
    PAS_AL1_TURN : BOOL;
END_VAR
VAR
    PPAL1 : BOOL := 1;
    PP0 : BOOL := 1;
    PP1 : BOOL := 0;
    PP2 : BOOL := 0;
    PP3 : BOOL := 0;
    PP4 : BOOL := 0;
    MCB : BOOL := 1;
    PP5 : BOOL := 0;
    PP7 : BOOL := 0;
    PPL3 : BOOL := 0;
    PPL4 : BOOL := 0;
    MCBR : BOOL := 1;
    PPL5 : BOOL := 0;
    PPL7 : BOOL := 0;
    STABLE : BOOL := 0;
    MCB_CONTROL : BOOL;
END_VAR

(* State Transition Logic *)
STABLE := 0;
WHILE (STABLE = 0) DO
    STABLE := 1;

    (* Main Path Transitions *)
    IF (PP0 = 1) AND (NOT MCB_CONTROL) AND (PP1 = 0) THEN
        PP0 := 0;
        PP1 := 1;
        STABLE := 0;
    END_IF;

    IF (PP1 = 1) AND S_AL1_P_B1 AND (PP2 = 0) THEN
        PP1 := 0;
        PP2 := 1;
        STABLE := 0;
    END_IF;

    IF (PP2 = 1) AND S_AL1_P_B2 AND (NOT MCB_CONTROL) AND (PP3 = 0) THEN
        PP2 := 0;
        PP3 := 1;
        STABLE := 0;
    END_IF;

    IF (PP3 = 1) AND S_AL1_MCB AND (PP4 = 0) AND (PP1 = 0) THEN
        PP3 := 0;
        PP4 := 1;
        PP1 := 1;
        STABLE := 0;
    END_IF;

    IF (PP4 = 1) AND (MCB = 1) AND MCB_BUSY AND (PP5 = 0) THEN
        PP4 := 0;
        MCB := 0;
        PP5 := 1;
        STABLE := 0;
    END_IF;

    IF (PP5 = 1) AND S_AL1_MCB2 AND (PP7 = 0) AND (MCB = 0) THEN
        PP5 := 0;
        PP7 := 1;
        MCB := 1;
        STABLE := 0;
    END_IF;

    IF (PP7 = 1) AND S_AL1_P_B3 THEN
        PP7 := 0;
        STABLE := 0;
    END_IF;

    (* Alternative Path Transitions *)
    IF (PP2 = 1) AND S_AL1_P_B2 AND MCB_CONTROL AND (PPL3 = 0) AND (PP1 = 0) THEN
        PP2 := 0;
        PPL3 := 1;
        PP1 := 1;
        STABLE := 0;
    END_IF;

    IF (PPL3 = 1) AND S_AL1_MCBR AND (PPL4 = 0) THEN
        PPL3 := 0;
        PPL4 := 1;
        STABLE := 0;
    END_IF;

    IF (PPL4 = 1) AND (MCBR = 1) AND MCBR_BUSY AND (PPL5 = 0) THEN
        PPL4 := 0;
        MCBR := 0;
        PPL5 := 1;
        STABLE := 0;
    END_IF;

    IF (PPL5 = 1) AND S_AL1_MCBR2 AND (PPL7 = 0) AND (MCBR = 0) THEN
        PPL5 := 0;
        PPL7 := 1;
        MCBR := 1;
        STABLE := 0;
    END_IF;

    IF (PPL7 = 1) AND S_AL1_P_B3 THEN
        PPL7 := 0;
        STABLE := 0;
    END_IF;
END_WHILE;

(* Output Control Logic *)
(* E_AL1_B1 - Circuit Activation *)
IF (PP0 = 1) OR (PP1 = 1) THEN
    E_AL1_B1 := 1;
ELSIF (PP2 = 1) OR (PP3 = 1) OR (PPL3 = 1) THEN
    E_AL1_B1 := 0;
ELSE
    E_AL1_B1 := 0;
END_IF;

(* MCB_CONTROL - Main Circuit Breaker Control *)
IF (PP3 = 1) THEN
    MCB_CONTROL := 1;
ELSIF (PP0 = 1) THEN
    MCB_CONTROL := 0;
END_IF;

(* PAS_AL1_PLUS and PAS_AL1_TURN - Process Activation Signals *)
IF (PPL3 = 1) OR (PPL4 = 1) THEN
    PAS_AL1_PLUS := 1;
    PAS_AL1_TURN := 1;
ELSIF (PP0 = 1) OR (PP3 = 1) OR (PP4 = 1) THEN
    PAS_AL1_PLUS := 0;
    PAS_AL1_TURN := 0;
ELSE
    PAS_AL1_PLUS := 0;
    PAS_AL1_TURN := 0;
END_IF;

(* PUWS_AL1_B1_PLUS - Plus Direction Control *)
IF (PPAL1 = 1) OR (PP2 = 1) THEN
    PUWS_AL1_B1_PLUS := 1;
ELSE
    PUWS_AL1_B1_PLUS := 0;
END_IF;

(* PUWS_AL1_B1_RIGHT - Right Direction Control *)
IF (PPAL1 = 1) OR (PP2 = 1) THEN
    PUWS_AL1_B1_RIGHT := 0;
ELSE
    PUWS_AL1_B1_RIGHT := 0;
END_IF;

END_FUNCTION_BLOCK;
